1856→    private void moveToDraftsFolderInBackground(Account account, long folderId, List<MessageReference> messages) {
1857→        for (MessageReference messageReference : messages) {
1858→            try {
1859→                Message message = loadMessage(account, folderId, messageReference.getUid());
1860→                Long draftMessageId = saveDraft(account, message, null, message.getSubject());
1861→
1862→                boolean draftSavedSuccessfully = draftMessageId != null;
1863→                if (draftSavedSuccessfully) {
1864→                    message.destroy();
1865→                }
1866→
1867→                for (MessagingListener listener : getListeners()) {
1868→                    listener.folderStatusChanged(account, folderId);
1869→                }
1870→            } catch (MessagingException e) {
1871→                Timber.e(e, "Error loading message. Draft was not saved.");
1872→            }
1873→        }
1874→    }
