1928→        try {
1929→            List<LocalMessage> messagesToDelete = collectMessagesInThreads(account, messages);
1930→            deleteMessagesSynchronous(account, folderId, messagesToDelete, skipTrashFolder);
1931→        } catch (MessagingException e) {
1932→            Timber.e(e, "Something went wrong while deleting threads");
