/**
 * Test for ArchiveOperations to verify that archiving messages marks them as read.
 */
class ArchiveOperationsTest {
    private lateinit var messagingController: MessagingController
    private lateinit var archiveOperations: ArchiveOperations
    private lateinit var localStoreProvider: LocalStoreProvider
    private lateinit var messageStoreManager: MessageStoreManager
    private lateinit var account: Account
    private lateinit var localStore: LocalStore
    private lateinit var sourceFolder: LocalFolder
    private lateinit var archiveFolder: LocalFolder
    private lateinit var messageStore: MessageStore
    private lateinit var localMessage: LocalMessage

    @Before
    fun setUp() {
        localStoreProvider = mock()
        messageStoreManager = mock()
        account = mock()
        localStore = mock()
        sourceFolder = mock()
        archiveFolder = mock()
        messageStore = mock()
        localMessage = mock()

        // Setup account
        whenever(account.uuid).thenReturn("test-account")
        whenever(account.archiveFolderId).thenReturn(ARCHIVE_FOLDER_ID)

        // Setup local store and folders
        whenever(localStoreProvider.getInstance(account)).thenReturn(localStore)
        whenever(localStore.getFolder(SOURCE_FOLDER_ID)).thenReturn(sourceFolder)
        whenever(localStore.getFolder(ARCHIVE_FOLDER_ID)).thenReturn(archiveFolder)

        // Setup source folder
        whenever(sourceFolder.databaseId).thenReturn(SOURCE_FOLDER_ID)
        whenever(sourceFolder.messagesByUids(anyList())).thenReturn(listOf(localMessage))

        // Setup archive folder
        whenever(archiveFolder.databaseId).thenReturn(ARCHIVE_FOLDER_ID)

        // Setup message
        whenever(localMessage.uid).thenReturn(MESSAGE_UID)
        whenever(localMessage.databaseId).thenReturn(MESSAGE_ID)
        whenever(localMessage.isSet(Flag.SEEN)).thenReturn(false) // Message is unread

        // Setup message store
        whenever(messageStoreManager.getMessageStore(account)).thenReturn(messageStore)
        whenever(messageStore.moveMessages(anyList(), anyLong())).thenReturn(
            mapOf(MESSAGE_ID to DESTINATION_MESSAGE_ID)
        )
        whenever(messageStore.getMessageServerIds(anyList())).thenReturn(
            mapOf(DESTINATION_MESSAGE_ID to MESSAGE_UID)
        )

        // Create MessagingController with mocked dependencies
        messagingController = mock()

        // Mock the moveOrCopyMessageSynchronous method to verify it's called with MOVE_AND_MARK_AS_READ
        whenever(
            messagingController.moveOrCopyMessageSynchronous(
                any(),
                anyLong(),
                anyList(),
                anyLong(),
                any()
            )
        ).thenAnswer { invocation ->
            // Verify that MOVE_AND_MARK_AS_READ flavor is used
            val flavor = invocation.getArgument<MessagingController.MoveOrCopyFlavor>(4)
            assert(flavor == MessagingController.MoveOrCopyFlavor.MOVE_AND_MARK_AS_READ) {
                "Expected MOVE_AND_MARK_AS_READ but got $flavor"
            }
            null
        }

        // Mock other required methods
        whenever(messagingController.actOnMessagesGroupedByAccountAndFolder(anyList(), any())).thenAnswer {
            invocation ->
            val messages = invocation.getArgument<List<MessageReference>>(0)
            val actor = invocation.getArgument<MessagingController.MessageActor>(1)

            // Simulate processing messages
            actor.act(account, sourceFolder, listOf(localMessage))
            null
        }

        archiveOperations = ArchiveOperations(messagingController)
    }

    @Test
    fun `archiveMessage should use MOVE_AND_MARK_AS_READ flavor`() {
        // Given: A message to archive
        val messageReference = MessageReference("test-account", SOURCE_FOLDER_ID, MESSAGE_UID)

        // When: Archiving the message
        archiveOperations.archiveMessage(messageReference)

        // Then: moveOrCopyMessageSynchronous should be called with MOVE_AND_MARK_AS_READ flavor
        verify(messagingController).moveOrCopyMessageSynchronous(
            eq(account),
            eq(SOURCE_FOLDER_ID),
            eq(listOf(localMessage)),
            eq(ARCHIVE_FOLDER_ID),
            eq(MessagingController.MoveOrCopyFlavor.MOVE_AND_MARK_AS_READ)
        )
    }

    @Test
    fun `archiveMessages should use MOVE_AND_MARK_AS_READ flavor`() {
        // Given: Multiple messages to archive
        val messageReferences = listOf(
            MessageReference("test-account", SOURCE_FOLDER_ID, MESSAGE_UID)
        )

        // When: Archiving the messages
        archiveOperations.archiveMessages(messageReferences)

        // Then: moveOrCopyMessageSynchronous should be called with MOVE_AND_MARK_AS_READ flavor
        verify(messagingController).moveOrCopyMessageSynchronous(
            eq(account),
            eq(SOURCE_FOLDER_ID),
            eq(listOf(localMessage)),
            eq(ARCHIVE_FOLDER_ID),
            eq(MessagingController.MoveOrCopyFlavor.MOVE_AND_MARK_AS_READ)
        )
    }

    companion object {
        private const val SOURCE_FOLDER_ID = 1L
        private const val ARCHIVE_FOLDER_ID = 2L
        private const val MESSAGE_ID = 100L
        private const val DESTINATION_MESSAGE_ID = 200L
        private const val MESSAGE_UID = "uid-123"
    }
}
